args.new_string:
defmodule PlanSync.Contract do
  @moduledoc false

  @paid_plan_codes ["team", "enterprise", "pro", "premium"]
  @contract_codes ["free", "paid_team"]

  @contracts %{
    "free" => %{
      billing_code: "free",
      warehouse_code: "free",
      amount_cents: 0,
      included_seats: 1,
      seat_band: "single",
      billable: false
    },
    "paid_team" => %{
      billing_code: "premium",
      warehouse_code: "pro",
      amount_cents: 4900,
      included_seats: 25,
      seat_band: "multi",
      billable: true
    }
  }

  def canonical_plan(plan) when plan in @paid_plan_codes, do: "paid_team"
  def canonical_plan(plan) when plan in @contract_codes, do: plan
  def canonical_plan(_plan), do: "free"

  def billing_plan_code(plan), do: contract_field(plan, :billing_code)
  def warehouse_plan_code(plan), do: contract_field(plan, :warehouse_code)
  def amount_cents(plan), do: contract_field(plan, :amount_cents)
  def included_seats(plan), do: contract_field(plan, :included_seats)
  def seat_band(plan), do: contract_field(plan, :seat_band)
  def billable?(plan), do: contract_field(plan, :billable)

  defp contract_field(plan, field) do
    plan
    |> canonical_plan()
    |> then(&Map.fetch!(@contracts, &1))
    |> Map.fetch!(field)
  end
end

